import React from "react";
import {
  HashRouter as Router,
  Route
} from "react-router-dom";
import About from './About'
import Design from './design/designWeek/Design'
import Coding from './coding/Coding'
import Fitness from './design/fitness/Fitness'
import DesignWeek from './design/designWeek/DesignWeek'
import PortfolioApp from './design/portfolioApp/PortfolioApp'
import QuantumComputing from './coding/quantum/QuantumComputing'
import SyntheticData from './coding/syntheticData/SyntheticData'
import GameDev from './coding/GameDev'

export default function AppRouter() {
  return (
    <Router basename="/">
    <Route exact path="/coding" component={Coding} />
    <Route path="/about" component={About} />
    <Route path="/design" component={ Design } />
    <Route path="/fitnessApp" component={ Fitness } />
    <Route path="/designWeek" component={ DesignWeek } />
    <Route path="/portfolioApp" component={ PortfolioApp } />
    <Route path="/quantumComputing" component={ QuantumComputing } />
    <Route path="/syntheticData" component={ SyntheticData } />
    <Route path="/gameDev" component={ GameDev } />

    </Router>
  );
}
